function LSdkHaoChenTrack:OnSelectGameServer()
    local serverId = gLGameLogin:GetServerId() or "0"
    local serverName = gLGameLogin:GetServerName() or ""
    local game_account_id = gLSdkImpl:CallMethod(LSdkMethod.GetSdkAccount) or ""
    self:SendTrackEvent(LSdkHaoChenTrack.AF_START_GAME_SUCC, "game_account_id", game_account_id, "serverId", serverId, "serverName", serverName)
end

function LSdkHaoChenTrack:OnPlayerLogin()
    local playerData = gLGameLogin:GetPlayerData()
    if not playerData then return end

    local game_account_id = gLSdkImpl:CallMethod(LSdkMethod.GetSdkAccount) or ""
    local serverId = gLGameLogin:GetServerId() or "0"
    local serverName = gLGameLogin:GetServerName() or ""
    local roleId = gLGameLogin:GetPlayerId() or "0"
    local roleName = playerData.name
    local roleLevel = tonumber(playerData.level) or 0
    local stageLevel = gModelInstance and gModelInstance:GetBattleNum() or 0
    self:SendTrackEvent(LSdkHaoChenTrack.AF_PLAYER_INFO_UPLOAD, "game_account_id", game_account_id, "serverId", serverId,
            "roleId", roleId, "roleName", roleName, "roleLevel", roleLevel, "big_StageLevel", stageLevel)
end

