function LSdkHaoChenTrack:OnMainBattleFinished(battleNode)
    if not battleNode then return end

    local ref = GameTable.MainInstanceMissionRef[battleNode]
    if not ref then return end

    local chapterId = ref.belongChapterId
    local playerData = gLGameLogin:GetPlayerData()
    if not playerData then return end

    local game_account_id = gLSdkImpl:CallMethod(LSdkMethod.GetSdkAccount) or ""
    local serverId = gLGameLogin:GetServerId() or "0"
    local serverName = gLGameLogin:GetServerName() or ""
    local roleId = gLGameLogin:GetPlayerId() or "0"
    local roleName = playerData.name
    local roleLevel = tonumber(playerData.level) or 0
    local traceName = _MissionDataList[battleNode]
    if traceName then
        self:SendTrackEvent(traceName, "game_account_id", game_account_id, "serverId", serverId, "serverName", serverName,
                "roleId", roleId, "roleName", roleName, "roleLevel", roleLevel)
    end
    self:SendTrackEvent(LSdkHaoChenTrack.AF_MAIN_STAGE_LEVEL, "game_account_id", game_account_id, "serverId", serverId, "serverName", serverName,
            "roleId", roleId, "roleName", roleName, "roleLevel", roleLevel)
end

