    self:SendTrackEvent(LSdkHaoChenTrack.AF_ROLE_LEVEL, "game_account_id", game_account_id, "serverId", serverId, "serverName", serverName,
            "roleId", roleId, "roleName", roleName, "roleLevel", roleLevel)
end

