function LSdkHaoChenTrack:OnCallHeroReward(callNum, callRefId, itemList, fixedReward)
    local nameList = {
        [1001] = "nvshen" -- 高级召唤
    }
    local name = nameList[callRefId]
    if string.isempty(name) then return end

    local afName = LSdkHaoChenTrack.AF_FIRST_RECRUIT
    if self:IsTrackRecorded(afName) then return end

    self:RecordedTrack(afName)

    local playerData = gLGameLogin:GetPlayerData()
    if not playerData then return end

    local game_account_id = gLSdkImpl:CallMethod(LSdkMethod.GetSdkAccount) or ""
    local serverId = gLGameLogin:GetServerId() or "0"
    local serverName = gLGameLogin:GetServerName() or ""
    local roleId = gLGameLogin:GetPlayerId() or "0"
    local roleName = playerData.name
    local roleLevel = tonumber(playerData.level) or 0
    self:SendTrackEvent(afName,"game_account_id", game_account_id, "serverId", serverId, "serverName", serverName,
            "roleId", roleId, "roleName", roleName, "roleLevel", roleLevel)
end

function LSdkHaoChenTrack:IsTrackRecorded(afName)
    local ids = gModelPlayer and gModelPlayer:GetFireOneTimeEventIds() or {}
    local id = LSdkHaoChenTrack.AF_IDS[afName]
    if not id then return true end
    
    if ids[id] then
        return true
    else
        return false
    end
end


function LSdkHaoChenTrack:RecordedTrack(afName)
    if not gModelPlayer then return end
    local id = LSdkHaoChenTrack.AF_IDS[afName]
    if not id then return end
    gModelPlayer:OnFireOnetimeEventReq(id)
end
